import requests
import json

class LLMProvider:
    """
    A provider class to interact with local LLMs via Ollama API.
    Allows switching between different models (Gemma, Llama, Qwen)
    based on the specific agent's requirements.
    """
    def __init__(self, base_url="http://localhost:11434"):
        self.base_url = base_url

    def generate(self, model_name, prompt, system_prompt=None, temperature=0.7):
        """
        Sends a prompt to the specified Ollama model and returns the text response.
        """
        url = f"{self.base_url}/api/generate"
        payload = {
            "model": model_name,
            "prompt": prompt,
            "system": system_prompt or "",
            "stream": False,
            "options": {
                "temperature": temperature
            }
        }

        try:
            response = requests.post(url, json=payload)
            response.raise_for_status()
            return response.json().get("response", "")
        except requests.exceptions.RequestException as e:
            return f"Error connecting to Ollama ({model_name}): {str(e)}"

    def generate_structured(self, model_name, prompt, system_prompt, schema):
        """
        Uses the 'format' parameter in Ollama to ensure the output matches a JSON schema.
        Note: This requires the model to be capable of JSON mode.
        """
        url = f"{self.base_url}/api/generate"
        payload = {
            "model": model_name,
            "prompt": prompt,
            "system": system_prompt,
            "stream": False,
            "format": "json", # Crucial for structured output
            "options": {"temperature": 0.1} # Lower temp for higher accuracy in JSON
        }

        try:
            response = requests.post(url, json=payload)
            response.raise_for_status()
            content = response.json().get("response", "{}")
            return json.loads(content)
        except Exception as e:
            return {"error": f"Structured generation failed for {model_name}: {str(e)}"}

if __name__ == "__main__":
    # Quick local test
    provider = LLMProvider()
    print("Testing connectivity to Ollama...")
    test_response = provider.generate("gemma4:26b", "Say 'System Online'")
    print(f"Response: {test_response}")

